"use client";

import { useState } from "react";
import { addComment } from "@/lib/comments";
import { MEMBERS } from "@/lib/supabase/supabase";

interface ChatProps {
    member?: string;
    onCommentAdded?: (comment: any) => void;
}

export default function Chat({ member = MEMBERS.CHANG, onCommentAdded }: ChatProps) {
    const [message, setMessage] = useState("");
    const [username, setUsername] = useState("");

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();

        if (!message.trim()) {
            alert("메시지를 입력해주세요!");
            return;
        }

        if (message.length > 40) {
            alert("메시지는 40자 이하로 입력해주세요!");
            return;
        }

        try {
            const result = await addComment(member as any, message, username);
            if (result) {
                setMessage("");
                setUsername("");
                console.log("Comment added successfully:", result);
                // 즉시 UI 업데이트를 위한 콜백 호출
                if (onCommentAdded) {
                    onCommentAdded(result);
                }
                alert("댓글이 성공적으로 추가되었습니다!");
            } else {
                alert("댓글 추가에 실패했습니다.");
            }
        } catch (error) {
            console.error("Error adding comment:", error);
            alert("댓글 추가 중 오류가 발생했습니다.");
        }
    }

    return (
        <div className="absolute bottom-0 left-1/2 -translate-x-1/2 z-10 w-1/3 py-4">
            <form className="flex items-center justify-center gap-2" onSubmit={handleSubmit}>
                <div className="w-5/6">
                    <input
                        type="text"
                        className="bg-white w-full rounded-lg p-2 border-2 text-black focus:outline-none"
                        placeholder="이채영 사랑해"
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                    />
                </div>
                <button type="submit" className="bg-black text-white rounded-lg p-2 hover:bg-black/50 w-1/6">Send</button>
            </form>
        </div >
    )
}