"use client";

import React, { useEffect, useState } from "react";
import Chat from "@/components/common/chat";
import { getComments, subscribeToComments, unsubscribeFromComments, addComment } from "@/lib/comments";
import { MEMBERS, Comment } from "@/lib/supabase/supabase";

type ActiveComment = {
    id: number;
    text: string;
    x: number;
    y: number;
    duration: number; // 유지 시간 (ms)
    username: string;
};

export default function Chang() {
    const [activeComments, setActiveComments] = useState<ActiveComment[]>([]);
    const [comments, setComments] = useState<Comment[]>([]);
    const [subscription, setSubscription] = useState<any>(null);
    let i = 0;

    // 👇 새 좌표 생성 (겹치지 않게)
    const getNonOverlappingPosition = (
        existing: ActiveComment[],
        maxAttempts = 20
    ) => {
        const padding = 100; // 최소 거리 (px) — 댓글 크기 감안
        let attempt = 0;

        while (attempt < maxAttempts) {
            const x = Math.random() * window.innerWidth * 0.7;
            const y = Math.random() * (window.innerHeight - 300) + 100; // 위아래 100px씩 여백

            // 기존 댓글과의 거리 검사
            const overlap = existing.some((c) => {
                const dx = c.x - x;
                const dy = c.y - y;
                return Math.sqrt(dx * dx + dy * dy) < padding;
            });

            if (!overlap) {
                return { x, y };
            }
            attempt++;
        }

        // 실패하면 그냥 랜덤 반환 (안 겹칠 확률이 높음)
        return {
            x: Math.random() * window.innerWidth * 0.7,
            y: Math.random() * (window.innerHeight - 500) + 300, // 위아래 100px씩 여백
        };
    };

    // Supabase에서 댓글 로드
    useEffect(() => {
        const loadComments = async () => {
            const data = await getComments(MEMBERS.CHANG);
            setComments(data);
        };
        loadComments();
    }, []);

    // 실시간 댓글 구독
    useEffect(() => {
        console.log('Setting up realtime subscription...');
        const sub = subscribeToComments(MEMBERS.CHANG, (newComment) => {
            console.log('Received new comment via subscription:', newComment);
            setComments(prev => {
                // 중복 방지
                const exists = prev.some(comment => comment.id === newComment.id);
                if (exists) {
                    console.log('Comment already exists, skipping...');
                    return prev;
                }
                console.log('Adding new comment to state');
                return [newComment, ...prev];
            });
        });
        setSubscription(sub);

        return () => {
            console.log('Cleaning up subscription...');
            unsubscribeFromComments(sub);
        };
    }, []);

    // 댓글을 화면에 표시하는 로직
    useEffect(() => {
        if (comments.length === 0) return;

        const interval = setInterval(() => {
            if (i >= comments.length) {
                i = 0;
            }

            const randomComment = comments[i];
            i++;

            const randomDuration =
                Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;

            setActiveComments((prev) => {
                if (prev.length >= 10) return prev;

                const pos = getNonOverlappingPosition(prev);

                const newComment: ActiveComment = {
                    id: randomComment.id,
                    text: randomComment.text,
                    x: pos.x,
                    y: pos.y,
                    duration: randomDuration,
                    username: randomComment.username,
                };

                // 댓글 추가
                const updated = [...prev, newComment];

                // 개별 제거 예약
                setTimeout(() => {
                    setActiveComments((cur) =>
                        cur.filter((c) => c.id !== newComment.id)
                    );
                }, randomDuration);

                return updated;
            });
        }, 2000);

        return () => clearInterval(interval);
    }, [comments]);

    return (
        <div className="relative w-screen h-screen  overflow-hidden">

            {/* 배경 이미지 */}
            <div className="absolute inset-0">
                <img
                    src="/hero/31.png"
                    alt="chang"
                    className="w-full h-full object-cover opacity-30"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-black/40"></div>
            </div>

            {activeComments.map((comment) => (
                <div
                    key={comment.id}
                    className="absolute opacity-0"
                    style={{
                        left: comment.x,
                        top: comment.y,
                        animation: `fadeInOut ${comment.duration}ms ease-in-out forwards`,
                    }}
                >
                    <p className="text-lg text-white">{comment.text}</p>
                    <p className="text-sm text-white text-right">{comment.username}</p>
                </div>
            ))}

            <Chat
                member={MEMBERS.CHANG}
                onCommentAdded={(newComment) => {
                    console.log('Comment added via callback:', newComment);
                    setComments(prev => {
                        // 중복 방지
                        const exists = prev.some(comment => comment.id === newComment.id);
                        if (exists) {
                            return prev;
                        }
                        return [newComment, ...prev];
                    });
                }}
            />

        </div>
    );
}
