import { supabase, Comment, Member, getCommentsTableName } from './supabase/supabase'

// 댓글 추가
export const addComment = async (member: Member, text: string, username: string): Promise<Comment | null> => {
    try {
        const tableName = getCommentsTableName(member)
        const { data, error } = await supabase
            .from(tableName)
            .insert({ text, username })
            .select()
            .single()

        if (error) {
            console.error('Error adding comment:', error)
            return null
        }

        return data
    } catch (error) {
        console.error('Error adding comment:', error)
        return null
    }
}

// 댓글 조회 (최신순)
export const getComments = async (member: Member, limit: number = 50): Promise<Comment[]> => {
    try {
        const tableName = getCommentsTableName(member)
        const { data, error } = await supabase
            .from(tableName)
            .select('*')
            .order('created_at', { ascending: false })
            .limit(limit)

        if (error) {
            console.error('Error fetching comments:', error)
            return []
        }

        return data || []
    } catch (error) {
        console.error('Error fetching comments:', error)
        return []
    }
}

// 실시간 댓글 구독
export const subscribeToComments = (member: Member, callback: (comment: Comment) => void) => {
    const tableName = getCommentsTableName(member)
    console.log(`Subscribing to ${tableName} changes...`)

    const channel = supabase
        .channel(`${tableName}_changes`)
        .on('postgres_changes',
            {
                event: 'INSERT',
                schema: 'public',
                table: tableName
            },
            (payload) => {
                console.log('New comment received:', payload)
                callback(payload.new as Comment)
            }
        )
        .subscribe((status) => {
            console.log(`Subscription status for ${tableName}:`, status)
            if (status === 'SUBSCRIBED') {
                console.log(`Successfully subscribed to ${tableName}`)
            } else if (status === 'CHANNEL_ERROR') {
                console.error(`Failed to subscribe to ${tableName}`)
            }
        })

    return channel
}

// 구독 해제
export const unsubscribeFromComments = (subscription: any) => {
    if (subscription) {
        supabase.removeChannel(subscription)
    }
}
